"""Evaluate models using various metrics."""

import argparse
import gzip
import json
import os
import pickle

from huggingface_hub import hf_hub_download

from xtalmet.constants import BINARY_DISTANCES, HF_VERSION
from xtalmet.evaluator import Evaluator

DISTANCES = [
	"smat",
	"comp",
	"wyckoff",
	"elmd",
	"amd",
	"elmd+amd",
]  #: Distance metrics to evaluate.


def eval(model: str) -> None:
	"""Evaluate crystals generated by a model using various metrics.

	Args:
		model (str): Model used to generate crystals.
	"""
	# Create directory to save results and intermediate files
	dir_save = os.path.join(os.path.dirname(__file__), "results", "mp20", model)
	os.makedirs(dir_save, exist_ok=True)
	# Load existing results if available
	if os.path.exists(os.path.join(dir_save, "results.json")):
		with open(os.path.join(dir_save, "results.json")) as f:
			results = json.load(f)
	else:
		results = {}
	for distance in DISTANCES:
		if distance not in results:
			results[distance] = {}
	# Download generated crystals
	path = hf_hub_download(
		repo_id="masahiro-negishi/xtalmet",
		filename=f"mp20/model/{model}.pkl.gz",
		repo_type="dataset",
		revision=HF_VERSION,
	)
	with gzip.open(path, "rb") as f:
		gen_xtals = pickle.load(f)
	# Evaluation
	for distance in DISTANCES:
		print(f"Evaluating {model} using {distance} distance...")
		arg_stability = "binary" if distance in BINARY_DISTANCES else "continuous"
		evaluator = Evaluator(
			validity=["smact", "structure"],
			stability=arg_stability,
			uniqueness=True,
			novelty=True,
			distance=distance,
			ref_xtals="mp20",
			agg_func="prod",
		)
		overall_score, _, times = evaluator.evaluate(
			xtals=gen_xtals,
			dir_intermediate=dir_save,
			multiprocessing=True,
			n_processes=10,
		)
		results[distance]["vsun"] = times | {"overall_score": overall_score}
	with open(os.path.join(dir_save, "results.json"), "w") as f:
		json.dump(results, f, indent=4, sort_keys=True)


if __name__ == "__main__":
	parser = argparse.ArgumentParser()
	parser.add_argument(
		"--model",
		type=str,
		required=True,
		choices=[
			"adit",
			"cdvae",
			"chemeleon",
			"chemeleon2",
			"diffcsp",
			"diffcsppp",
			"mattergen",
			"test",
			"chemeleon2_rl_bsun",
			"chemeleon2_rl_csun",
			"chemeleon2_rl_csun_u10",
		],
		help="Model used to generate crystals.",
	)
	args = parser.parse_args()
	eval(**vars(args))
